/**
 * Pulls a balanced string off the queue. E.g. if queue is "(one (two) three) four", (,) will return "one (two) three",
 * and leave " four" on the queue. Unbalanced openers and closers can quoted (with ' or ") or escaped (with \). Those escapes will be left
 * in the returned string, which is suitable for regexes (where we need to preserve the escape), but unsuitable for
 * contains text strings; use unescape for that.
 * @param open opener
 * @param close closer
 * @return data matched from the queue
 */
public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean inSingleQuote = false;
    boolean inDoubleQuote = false;

    while (!isEmpty()) {
        Character c = consume();

        // Handle quotes - if not escaped
        if (last != ESC) {
            if (c == '\'' && !inDoubleQuote) {
                inSingleQuote = !inSingleQuote;
            } else if (c == '"' && !inSingleQuote) {
                inDoubleQuote = !inDoubleQuote;
            }
        }

        // Only consider bracket depth when not inside quotes
        if (!inSingleQuote && !inDoubleQuote) {
            if (last != ESC) {
                if (c == open) {
                    if (depth == 0) {
                        // We're at the first opening bracket, so the content starts after it
                        start = pos;  // pos is now at the character after the opening bracket
                    }
                    depth++;
                }
                else if (c == close) {
                    depth--;
                    if (depth == 0) {
                        // We've reached the matching closing bracket, content ends before this bracket
                        end = pos - 1;  // pos is now at the character after the closing bracket, so we subtract 1
                        break;  // We found the balanced pair, exit the loop
                    }
                }
            }
        } else {
            // When inside quotes, handle the opening/closing brackets as regular chars
            // but still check for the escape character
            if (c == open && depth == 0 && start == -1) {
                // Even if inside quotes, we still need to know where content starts after the first opening bracket
                start = pos;
            }
        }

        last = c;
    }

    return (start != -1 && end >= start) ? queue.substring(start, end) : "";
}

